commit fe117f9c3aef4f06da990d411fc177c16ddacaad
Author: Terry Kong <terryk@nvidia.com>
Date:   Tue Jan 16 10:47:41 2024 -0800

    Added feature to specify multiple IB resources for trianing k8s
    template.

    Example:

    - multiple
    ```
    'cluster.ib_resource_name=[4,5]' 'cluster.ib_count=[1,2]'
    ```
    - single
    ```
    'cluster.ib_resource_name=aa' 'cluster.ib_count=4'
    ```
---
 .../core/k8s_templates/training/training.yaml          | 18 ++++++++++++++++--
 1 file changed, 16 insertions(+), 2 deletions(-)

diff --git a/launcher_scripts/nemo_launcher/core/k8s_templates/training/training.yaml b/launcher_scripts/nemo_launcher/core/k8s_templates/training/training.yaml
index 4cdd2905..b613bff9 100644
--- a/launcher_scripts/nemo_launcher/core/k8s_templates/training/training.yaml
+++ b/launcher_scripts/nemo_launcher/core/k8s_templates/training/training.yaml
@@ -1,4 +1,6 @@
 {{ $config := .Values.trainingConfig }}
+{{ $ibResourceName := .Values.trainingConfig.ibResourceName }}
+{{ $ibCount := .Values.trainingConfig.ibCount }}

 apiVersion: kubeflow.org/v1
 kind: PyTorchJob
@@ -42,10 +44,22 @@ spec:
             resources:
               requests:
                 nvidia.com/gpu: {{ .Values.image.numGPUs }}
-                {{ $config.ibResourceName }}: {{ $config.ibCount }}
+                {{- if and (kindIs "slice" $ibResourceName) (kindIs "slice" $ibCount) }}
+                {{- range $i, $val := $ibResourceName }}
+                {{ $val }}: {{ index $ibCount $i }}
+                {{- end }}
+                {{- else }}
+                {{ $ibResourceName }}: {{ $ibCount }}
+                {{- end }}
               limits:
                 nvidia.com/gpu: {{ .Values.image.numGPUs }}
-                {{ $config.ibResourceName }}: {{ $config.ibCount }}
+                {{- if and (kindIs "slice" $ibResourceName) (kindIs "slice" $ibCount) }}
+                {{- range $i, $val := $ibResourceName }}
+                {{ $val }}: {{ index $ibCount $i }}
+                {{- end }}
+                {{- else }}
+                {{ $ibResourceName }}: {{ $ibCount }}
+                {{- end }}
             volumeMounts:
             - mountPath: {{ $config.NFSPath }}
               name: workspace

